WITH ranked_pairs AS (SELECT f.Carrier, f.OriginCode, a.DisplayAirportName, count() AS winter_flights, round(avg(if(f.DepDel15 = 0, 1.0, 0.0)) * 100, 2) AS dep_otp_pct, round(avg(ifNull(toFloat64(f.DepDelay), 0.0)), 2) AS avg_dep_delay_min, countIf((f.CarrierDelay IS NOT NULL) OR (f.WeatherDelay IS NOT NULL) OR (f.NASDelay IS NOT NULL) OR (f.SecurityDelay IS NOT NULL) OR (f.LateAircraftDelay IS NOT NULL)) AS flights_with_any_reported_cause, countIf((f.CarrierDelay IS NULL) AND (f.WeatherDelay IS NULL) AND (f.NASDelay IS NULL) AND (f.SecurityDelay IS NULL) AND (f.LateAircraftDelay IS NULL)) AS flights_without_reported_cause FROM ontime.fact_ontime AS f LEFT JOIN ontime.dim_airports AS a ON f.OriginAirportID = a.AirportID WHERE f.Month IN (12, 1, 2) AND f.Cancelled = 0 AND f.Diverted = 0 GROUP BY f.Carrier, f.OriginCode, a.DisplayAirportName HAVING winter_flights >= 1000) SELECT Carrier, OriginCode, DisplayAirportName, winter_flights, dep_otp_pct, avg_dep_delay_min, flights_with_any_reported_cause, flights_without_reported_cause FROM ranked_pairs ORDER BY dep_otp_pct ASC, avg_dep_delay_min DESC, winter_flights DESC LIMIT 25
